const body = $json.body ?? $json;
const text = String(body.text ?? body.review ?? '').toLowerCase();
const rating = Number(body.rating ?? 0);
const severeTerms = ['sick', 'food poisoning', 'allergy', 'unsafe', 'injury', 'raw'];
const serviceTerms = ['rude', 'wait', 'late', 'missing', 'cold'];
const severe = rating <= 2 || severeTerms.some((term) => text.includes(term));
const service = serviceTerms.some((term) => text.includes(term));
let priority = 'normal';
let owner = 'store_manager';
let posture = 'thank_and_invite_back';
if (severe) {
  priority = 'urgent';
  owner = 'district_manager';
  posture = 'apologize_take_offline_document_incident';
} else if (service || rating <= 3) {
  priority = 'same_day';
  owner = 'shift_lead';
  posture = 'acknowledge_specific_issue_offer_resolution';
}
return [{
  json: {
    workflow: 'qsr-review-triage-desk',
    source: body.source ?? 'unknown',
    storeId: body.storeId ?? 'unknown',
    rating,
    priority,
    owner,
    responsePosture: posture,
    responseStatus: 'draft_for_human_approval',
    complianceNote: severe ? 'Document internally before public response.' : 'No safety trigger detected by keyword rules.'
  }
}];
